mapper.select:
/*CsBookingMapper.selectBookingCd*/ SELECT GRP_ID, CD_VAL, CD_DSC, ETC1, ETC2 FROM CMN_GRP_CD_MST@DL_MSP WHERE NVL(USG_YN, 'N') = 'Y' AND GRP_ID = #{grpId}
AND ETC2 = #{etc2}
ORDER BY ETC1

/*CsBookingMapper.getBookingTimeList*/ SELECT CS_RES_DT, CS_RES_TM, CS_RES_TM_NM, CASE WHEN (PER_CNT-RES_CNT) <= 0 THEN 'N' WHEN TO_DATE((CS_RES_DT),'YYYYMMDD') <= SYSDATE THEN 'N' ELSE 'Y' END AS REMAIN_YN FROM ( SELECT A.CS_RES_DT, A.CS_RES_TM, A.PER_CNT, FN_GET_CODENM@DL_MSP('VOC0024',A.CS_RES_TM)AS CS_RES_TM_NM, (SELECT COUNT(CS_RES_SEQ) FROM MSP_CS_RES_CSTMR@DL_MSP B WHERE B.CS_RES_DT=#{csResDt} AND B.CS_RES_TM= A.CS_RES_TM AND NVL(B.DEL_YN, 'N') != 'Y') AS RES_CNT FROM MSP_CS_RES@DL_MSP A WHERE A.CS_RES_DT = #{csResDt}
AND A.CS_RES_TM = #{csResTm}
) ORDER BY CS_RES_TM

/*CsBookingMapper.overNum*/
SELECT
    COUNT(CS_RES_SEQ) AS CNT,
    (CASE WHEN (TO_DATE(#{csResDt}, 'YYYYMMDD')<= SYSDATE) THEN 'N'
          ELSE 'Y' END) AS POSSIBLE
FROM MSP_CS_RES_CSTMR@DL_MSP
WHERE CS_RES_DT=#{csResDt}
AND CONTRACT_NUM = #{contractNum}
AND NVL(DEL_YN,'N')!='Y'

mapper.insert:
/*CsBookingMapper.insertBooking*/
SELECT (TO_CHAR(SYSDATE,'YYYYMMDD')||TRIM(TO_CHAR(SQ_CS_RES_CSTMR.NEXTVAL@DL_MSP, '0000')))AS csResSeq, TO_CHAR(SYSDATE,'YYYYMMDD') AS regstDt, SYSDATE AS regstDttm FROM DUAL
INSERT INTO MSP_CS_RES_CSTMR@DL_MSP( CS_RES_SEQ, CS_RES_DT, CS_RES_TM, USR_ID, CONTRACT_NUM, VOC_FIR, VOC_SEC, VOC_THI, VOC_DTL, CS_SUBJECT, CS_CONTENT, REGST_DT, REGST_DTTM, CS_STAT_CD ) VALUES ( #{csResSeq}, #{csResDt}, #{csResTm}, #{usrId}, #{contractNum}, #{vocFir}, #{vocSec}, #{vocThi}, #{vocDtl}, #{csSubject}, #{csContent}, #{regstDt}, #{regstDttm}, 'RCP' )

mapper.update:
/*CsBookingMapper.updateDelYn*/
UPDATE MSP_CS_RES_CSTMR@DL_MSP
SET DEL_YN='Y', CS_STAT_CD=NULL
WHERE CS_RES_SEQ=#{csResSeq}
